/**
 * TypeScript bridge to the core UniFFI native module.
 *
 * The native module (generated by UniFFI) is loaded as 'gardens_core' via the
 * React Native TurboModule / JSI bridge.  During unit tests or web preview
 * we fall back to a JS stub so the module can be imported without crashing.
 */

import { NativeModules, TurboModuleRegistry } from 'react-native';

export interface KeyPair {
  privateKeyHex: string; // 64 hex chars — Ed25519 private key seed
  publicKeyHex: string;  // 64 hex chars — peer identity
  mnemonic: string;      // 24 space-separated BIP-39 words
}

export class KeyError extends Error {
  constructor(
    public readonly kind: 'InvalidMnemonic' | 'InvalidPrivateKey',
    message: string,
  ) {
    super(message);
    this.name = 'KeyError';
  }
}

// ── Phase 3 types ──────────────────────────────────────────────────────────────

export type ConnectionStatus = 'Online' | 'Connecting' | 'Offline';

// ── Data types ────────────────────────────────────────────────────────────────

export interface Profile {
  publicKey: string;
  username: string;
  avatarBlobId: string | null;
  bio: string | null;
  availableFor: string[];
  isPublic: boolean;
  emailEnabled?: boolean;
  createdAt: number;
  updatedAt: number;
}

export interface PkarrResolved {
  recordType: string;
  name: string | null;
  username: string | null;
  description: string | null;
  bio: string | null;
  avatarBlobId: string | null;
  coverBlobId: string | null;
  publicKey: string;
  email: boolean;
}

export interface OnionHopFfi {
  pubkeyHex: string;
  nextUrl: string;
}


export interface OnionPeeled {
  peelType: 'forward' | 'deliver';
  nextHopUrl: string | null;
  innerPacket: Uint8Array | null;
  topicId: Uint8Array | null;
  op: Uint8Array | null;
}

export interface OrgSummary {
  orgId: string;
  name: string;
  typeLabel: string;
  description: string | null;
  avatarBlobId: string | null;
  coverBlobId: string | null;
  welcomeText: string | null;
  customEmojiJson: string | null;
  orgCooldownSecs: number | null;
  isPublic: boolean;
  emailEnabled?: boolean;
  creatorKey: string;
  orgPubkey: string | null;  // Org's z32-encoded public key for pkarr
  createdAt: number;
}

export interface Room {
  roomId: string;
  orgId: string;
  name: string;
  createdBy: string;
  createdAt: number;
  encKeyEpoch: number;
  isArchived: boolean;
  archivedAt: number | null;
  roomCooldownSecs: number | null;
}

export interface Event {
  eventId: string;
  orgId: string;
  title: string;
  description: string | null;
  locationType: string;
  locationText: string | null;
  locationRoomId: string | null;
  startAt: number;
  endAt: number | null;
  createdBy: string;
  createdAt: number;
  isDeleted: boolean;
}

export interface EventRsvp {
  eventId: string;
  memberKey: string;
  status: string;
  updatedAt: number;
}

export interface IceInfo {
  publicKey: string;
  icedUntil: number;
}

export interface Message {
  messageId: string;
  roomId: string | null;
  dmThreadId: string | null;
  authorKey: string;
  contentType: string;
  textContent: string | null;
  blobId: string | null;
  embedUrl: string | null;
  mentions: string[];
  replyTo: string | null;
  timestamp: number;
  editedAt: number | null;
  isDeleted: boolean;
}

export interface Reaction {
  messageId: string;
  emoji: string;
  reactorKey: string;
}

export interface DmThread {
  threadId: string;
  initiatorKey: string;
  recipientKey: string;
  createdAt: number;
  lastMessageAt: number | null;
  isRequest: boolean;
}

/** Returned by sendMessage and createDmThread. op_bytes must be forwarded via onion routing. */
export interface SendResult {
  /** message_id or thread_id (op hash hex) */
  id: string;
  /** GossipEnvelope CBOR bytes (if you need to forward or store externally) */
  opBytes: Uint8Array;
}

// ── Phase 5 types ──────────────────────────────────────────────────────────────

export class AuthError extends Error {
  constructor(
    public readonly kind: 'InvalidSignature' | 'TokenExpired' | 'Unauthorized' | 'NotInitialised',
    message: string,
  ) {
    super(message);
    this.name = 'AuthError';
  }
}

export interface InviteTokenInfo {
  orgId: string;
  inviterKey: string;
  accessLevel: string;
  expiryTimestamp: number;
}

export interface MemberInfo {
  publicKey: string;
  accessLevel: string;
  joinedAt: number;
}

// ── Native module interface ───────────────────────────────────────────────────

interface GardensCoreNative {
  // Phase 1
  generateKeypair(): Promise<KeyPair>;
  importFromMnemonic(words: string[]): Promise<KeyPair>;
  // Phase 2
  initCore(privateKeyHex: string, dbDir: string): Promise<void>;
  // Network
  initNetwork(relayUrl: string | null): Promise<string>;
  isNetworkInitialized(): Promise<boolean>;
  getNodeId(): Promise<string>;
  createOrUpdateProfile(username: string, bio: string | null, availableFor: string[], isPublic: boolean, avatarBlobId: string | null, emailEnabled: boolean): Promise<void>;
  getPkarrUrl(publicKeyHex: string): string;
  getPkarrUrlFromZ32(z32Key: string): string;
  resolvePkarr(z32Key: string): Promise<PkarrResolved | null>;
  getMyProfile(): Promise<Profile | null>;
  getProfile(publicKey: string): Promise<Profile | null>;
  createOrg(name: string, typeLabel: string, description: string | null, isPublic: boolean): Promise<string>;
  listMyOrgs(): Promise<OrgSummary[]>;
  updateOrg(orgId: string, name: string | null, typeLabel: string | null, description: string | null, avatarBlobId: string | null, coverBlobId: string | null, welcomeText: string | null, customEmojiJson: string | null, orgCooldownSecs: number | null, isPublic: boolean | null, emailEnabled: boolean | null): Promise<string>; // returns base64 op bytes
  createRoom(orgId: string, name: string): Promise<string>;
  listRooms(orgId: string, includeArchived: boolean): Promise<Room[]>;
  updateRoom(orgId: string, roomId: string, name: string | null, roomCooldownSecs: number | null): Promise<void>;
  setRoomCooldown(orgId: string, roomId: string, cooldownSecs: number): Promise<void>;
  deleteRoom(orgId: string, roomId: string): Promise<void>;
  archiveRoom(orgId: string, roomId: string): Promise<void>;
  unarchiveRoom(orgId: string, roomId: string): Promise<void>;
  createEvent(
    orgId: string,
    title: string,
    description: string | null,
    locationType: string,
    locationText: string | null,
    locationRoomId: string | null,
    startAt: number,
    endAt: number | null,
  ): Promise<{ id: string; opBytesBase64: string }>;
  updateEvent(
    orgId: string,
    eventId: string,
    title: string | null,
    description: string | null,
    locationType: string | null,
    locationText: string | null,
    locationRoomId: string | null,
    startAt: number | null,
    endAt: number | null,
  ): Promise<string>; // returns base64 op bytes
  deleteEvent(orgId: string, eventId: string): Promise<string>; // returns base64 op bytes
  listEvents(orgId: string): Promise<Event[]>;
  setEventRsvp(eventId: string, status: string): Promise<string>; // returns base64 op bytes
  clearEventRsvp(eventId: string): Promise<string>; // returns base64 op bytes
  listEventRsvps(eventId: string): Promise<EventRsvp[]>;
  sendMessage(
    roomId: string | null,
    dmThreadId: string | null,
    contentType: string,
    textContent: string | null,
    blobId: string | null,
    embedUrl: string | null,
    mentions: string[],
    replyTo: string | null,
  ): Promise<{ id: string; opBytesBase64: string }>;
  listMessages(
    roomId: string | null,
    dmThreadId: string | null,
    limit: number,
    beforeTimestamp: number | null,
  ): Promise<Message[]>;
  addReaction(messageId: string, emoji: string): Promise<{ id: string; opBytesBase64: string }>;
  removeReaction(messageId: string, emoji: string): Promise<{ id: string; opBytesBase64: string }>;
  listReactions(messageIds: string[]): Promise<Reaction[]>;
  deleteMessage(messageId: string, orgId: string | null): Promise<{ id: string; opBytesBase64: string }>;
  createDmThread(recipientKey: string): Promise<{ id: string; opBytesBase64: string }>;
  listDmThreads(): Promise<DmThread[]>;
  acceptMessageRequest(threadId: string): Promise<void>;
  declineMessageRequest(threadId: string): Promise<void>;
  // Phase 3
  getConnectionStatus(): Promise<ConnectionStatus>;
  searchPublicOrgs(query: string): Promise<OrgSummary[]>;
  // Phase 5
  generateInviteToken(orgId: string, accessLevel: string, expiryTimestamp: number): string;
  verifyInviteToken(tokenBase64: string, currentTimestamp: number): InviteTokenInfo;
  addMemberDirect(orgId: string, memberPublicKey: string, accessLevel: string): Promise<void>;
  removeMemberFromOrg(orgId: string, memberPublicKey: string): Promise<void>;
  changeMemberPermission(orgId: string, memberPublicKey: string, newAccessLevel: string): Promise<void>;
  listOrgMembers(orgId: string): Promise<MemberInfo[]>;
  setUserCooldown(orgId: string, memberPublicKey: string, cooldownSecs: number): Promise<void>;
  iceMember(orgId: string, memberPublicKey: string, durationSecs: number): Promise<void>;
  uniceMember(orgId: string, memberPublicKey: string): Promise<void>;
  listIcedMembers(orgId: string): Promise<IceInfo[]>;
  setOrgCooldown(orgId: string, cooldownSecs: number): Promise<void>;
  deleteOrg(orgId: string): Promise<void>;
  // Member moderation (stubs)
  kickMember(orgId: string, memberPublicKey: string): Promise<void>;
  banMember(orgId: string, memberPublicKey: string): Promise<void>;
  unbanMember(orgId: string, memberPublicKey: string): Promise<void>;
  muteMember(orgId: string, memberPublicKey: string, durationSeconds: number): Promise<void>;
  unmuteMember(orgId: string, memberPublicKey: string): Promise<void>;
  ignoreUser(publicKey: string): Promise<void>;
  unignoreUser(publicKey: string): Promise<void>;
  listIgnoredUsers(): Promise<string[]>;
  // Phase 7 — binary data is base64-encoded over the RN bridge
  prepareOutboundEmail(
    to: string,
    subject: string,
    bodyText: string,
    bodyHtml: string | null,
    replyToMessageId: string | null,
  ): Promise<string>; // returns JSON: { signed_payload: string, signature: string }
  uploadBlob(dataBase64: string, mimeType: string, roomId: string | null): Promise<string>;
  getBlob(blobHash: string, roomId: string | null): Promise<string>; // returns base64
  hasBlob(blobHash: string): Promise<boolean>;
  requestBlobFromPeer(blobHash: string, peerPublicKey: string, timeoutSecs: number): Promise<string | null>; // returns base64 or null
  provideBlobToPeer(blobHash: string, peerPublicKey: string): Promise<void>;
  // Sync — receive op from TopicDO WebSocket
  ingestOpFfi(topicHex: string, seq: number, opBytesBase64: string): Promise<void>;
  getTopicSeqFfi(topicHex: string): Promise<number>;
  // Onion routing — bytes are base64-encoded over the RN bridge
  buildOnionPacket(hops: OnionHopFfi[], topicIdBase64: string, opBase64: string): Promise<string>; // returns base64
  peelOnionLayer(packetBase64: string, recipientSeedHex: string): Promise<{
    peelType: string;
    nextHopUrl: string | null;
    innerPacketBase64: string | null;
    topicIdBase64: string | null;
    opBase64: string | null;
  }>;
}

function loadNative(): GardensCoreNative {
  try {
    // Prefer TurboModule if available, fallback to legacy NativeModules
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const turbo = (TurboModuleRegistry as any)?.get?.('GardensCore');
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const legacy = (NativeModules as any)?.GardensCore;
    const mod = (turbo || legacy) as GardensCoreNative | undefined;
    if (mod) {
      return mod;
    }
    throw new Error('GardensCore native module not loaded');
  } catch {
    return {
      async generateKeypair(): Promise<KeyPair> {
        throw new Error('gardens_core native module not loaded');
      },
      async importFromMnemonic(_words: string[]): Promise<KeyPair> {
        throw new Error('gardens_core native module not loaded');
      },
      async initCore() { throw new Error('gardens_core native module not loaded'); },
      async initNetwork() { throw new Error('gardens_core native module not loaded'); },
      async isNetworkInitialized() { return false; },
      async getNodeId() { throw new Error('gardens_core native module not loaded'); },
      async createOrUpdateProfile(_u: string, _b: string | null, _a: string[], _p: boolean, _av: string | null, _em: boolean) { throw new Error('gardens_core not loaded'); },
      getPkarrUrl() { throw new Error('gardens_core not loaded'); },
      getPkarrUrlFromZ32() { throw new Error('gardens_core not loaded'); },
      async resolvePkarr() { return null; },
      async getMyProfile() { return null; },
      async getProfile() { return null; },
      async createOrg() { throw new Error('gardens_core not loaded'); },
      async listMyOrgs() { return []; },
      async updateOrg() { throw new Error('gardens_core not loaded'); },
      async createRoom() { throw new Error('gardens_core not loaded'); },
      async listRooms() { return []; },
      async updateRoom() { throw new Error('gardens_core not loaded'); },
      async setRoomCooldown() { throw new Error('gardens_core not loaded'); },
      async deleteRoom() { throw new Error('gardens_core not loaded'); },
      async archiveRoom() { throw new Error('gardens_core not loaded'); },
      async unarchiveRoom() { throw new Error('gardens_core not loaded'); },
      async createEvent() { throw new Error('gardens_core not loaded'); },
      async updateEvent() { throw new Error('gardens_core not loaded'); },
      async deleteEvent() { throw new Error('gardens_core not loaded'); },
      async listEvents() { return []; },
      async setEventRsvp() { throw new Error('gardens_core not loaded'); },
      async clearEventRsvp() { throw new Error('gardens_core not loaded'); },
      async listEventRsvps() { return []; },
      async sendMessage() { throw new Error('gardens_core not loaded'); },
      async listMessages() { return []; },
      async addReaction() { throw new Error('gardens_core not loaded'); },
      async removeReaction() { throw new Error('gardens_core not loaded'); },
      async listReactions() { return []; },
      async deleteMessage() { throw new Error('gardens_core not loaded'); },
      async createDmThread() { throw new Error('gardens_core not loaded'); },
      async listDmThreads() { return []; },
      async acceptMessageRequest() { throw new Error('gardens_core not loaded'); },
      async declineMessageRequest() { throw new Error('gardens_core not loaded'); },
      async getConnectionStatus() { return 'Offline'; },
      async searchPublicOrgs() { return []; },
      generateInviteToken() { throw new Error('gardens_core not loaded'); },
      verifyInviteToken() { throw new Error('gardens_core not loaded'); },
      async addMemberDirect() { throw new Error('gardens_core not loaded'); },
      async removeMemberFromOrg() { throw new Error('gardens_core not loaded'); },
      async changeMemberPermission() { throw new Error('gardens_core not loaded'); },
      async listOrgMembers() { return []; },
      async setUserCooldown() { throw new Error('gardens_core not loaded'); },
      async iceMember() { throw new Error('gardens_core not loaded'); },
      async uniceMember() { throw new Error('gardens_core not loaded'); },
      async listIcedMembers() { return []; },
      async setOrgCooldown() { throw new Error('gardens_core not loaded'); },
      async deleteOrg() { throw new Error('gardens_core not loaded'); },
      async kickMember() { throw new Error('gardens_core not loaded'); },
      async banMember() { throw new Error('gardens_core not loaded'); },
      async unbanMember() { throw new Error('gardens_core not loaded'); },
      async muteMember() { throw new Error('gardens_core not loaded'); },
      async unmuteMember() { throw new Error('gardens_core not loaded'); },
      async ignoreUser() { throw new Error('gardens_core not loaded'); },
      async unignoreUser() { throw new Error('gardens_core not loaded'); },
      async listIgnoredUsers() { return []; },
      async uploadBlob() { throw new Error('gardens_core not loaded'); },
      async getBlob() { throw new Error('gardens_core not loaded'); },
      async hasBlob() { return false; },
      async requestBlobFromPeer() { return null; },
      async provideBlobToPeer() { throw new Error('gardens_core not loaded'); },
      async ingestOpFfi() { throw new Error('gardens_core not loaded'); },
      async getTopicSeqFfi() { return 0; },
      async buildOnionPacket() { throw new Error('gardens_core not loaded'); },
      async peelOnionLayer() { throw new Error('gardens_core not loaded'); },
      async prepareOutboundEmail() { throw new Error('gardens_core not loaded'); },
    };
  }
}

const native = loadNative();

// ── Phase 1 exports ───────────────────────────────────────────────────────────

/** Generate a fresh Ed25519 keypair and 24-word BIP-39 mnemonic. */
export async function generateKeypair(): Promise<KeyPair> {
  return native.generateKeypair();
}

/**
 * Re-derive a keypair from an existing 24-word mnemonic.
 * Throws {@link KeyError} if the mnemonic is invalid.
 */
export async function importFromMnemonic(words: string[]): Promise<KeyPair> {
  try {
    return await native.importFromMnemonic(words);
  } catch (err: unknown) {
    if (err instanceof Error && err.message.includes('InvalidMnemonic')) {
      throw new KeyError('InvalidMnemonic', err.message);
    }
    throw err;
  }
}

// ── Phase 2/Profile exports ───────────────────────────────────────────────────

export async function createOrUpdateProfile(
  username: string,
  bio: string | null,
  availableFor: string[],
  isPublic: boolean = false,
  avatarBlobId: string | null = null,
  emailEnabled: boolean = false,
): Promise<void> {
  return native.createOrUpdateProfile(username, bio, availableFor, isPublic, avatarBlobId, emailEnabled);
}

export function getPkarrUrl(publicKeyHex: string): string {
  try {
    return native.getPkarrUrl(publicKeyHex);
  } catch (err: unknown) {
    if (err instanceof Error) {
      throw new Error(`Failed to get pkarr URL: ${err.message}`);
    }
    throw err;
  }
}

/// Get pkarr URL from a z32-encoded public key (for orgs).
/// Input: z32-encoded key (e.g., "yj4bqhvahk8dge...")
/// Returns: `pk:<z32-encoded-pubkey>`
export function getPkarrUrlFromZ32(z32Key: string): string {
  try {
    return native.getPkarrUrlFromZ32(z32Key);
  } catch (err: unknown) {
    if (err instanceof Error) {
      throw new Error(`Failed to get pkarr URL from z32: ${err.message}`);
    }
    throw err;
  }
}

export async function resolvePkarr(z32Key: string): Promise<PkarrResolved | null> {
  return native.resolvePkarr(z32Key);
}

export async function getMyProfile(): Promise<Profile | null> {
  return native.getMyProfile();
}

export async function getProfile(publicKey: string): Promise<Profile | null> {
  return native.getProfile(publicKey);
}

