// ── Phase 7: Blobs ────────────────────────────────────────────────────────────

export class BlobError extends Error {
  constructor(
    public readonly kind: 'NotInitialized' | 'NotFound' | 'StoreError' | 'IoError',
    message: string,
  ) {
    super(message);
    this.name = 'BlobError';
  }
}

export async function uploadBlob(
  data: Uint8Array,
  mimeType: string,
  roomId: string | null,
): Promise<string> {
  let binary = '';
  for (let i = 0; i < data.byteLength; i++) { binary += String.fromCharCode(data[i]); }
  return native.uploadBlob(btoa(binary), mimeType, roomId);
}

export async function getBlob(blobHash: string, roomId: string | null): Promise<Uint8Array> {
  const base64 = await native.getBlob(blobHash, roomId);
  const binary = atob(base64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) { bytes[i] = binary.charCodeAt(i); }
  return bytes;
}

export async function hasBlob(blobHash: string): Promise<boolean> {
  return native.hasBlob(blobHash);
}

export async function requestBlobFromPeer(
  blobHash: string,
  peerPublicKey: string,
  timeoutSecs: number = 30,
): Promise<Uint8Array | null> {
  const base64 = await native.requestBlobFromPeer(blobHash, peerPublicKey, timeoutSecs);
  if (!base64) return null;
  const binary = atob(base64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) { bytes[i] = binary.charCodeAt(i); }
  return bytes;
}

export async function provideBlobToPeer(
  blobHash: string,
  peerPublicKey: string,
): Promise<void> {
  return native.provideBlobToPeer(blobHash, peerPublicKey);
}

// ── Onion routing ─────────────────────────────────────────────────────────────

function bytesToBase64(bytes: Uint8Array): string {
  let binary = '';
  for (let i = 0; i < bytes.byteLength; i++) { binary += String.fromCharCode(bytes[i]); }
  return btoa(binary);
}

function base64ToBytes(base64: string): Uint8Array {
  const binary = atob(base64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) { bytes[i] = binary.charCodeAt(i); }
  return bytes;
}

// ── Sync ─────────────────────────────────────────────────────────────────────

export async function ingestOp(topicHex: string, seq: number, opBytes: Uint8Array): Promise<void> {
  return native.ingestOpFfi(topicHex, seq, bytesToBase64(opBytes));
}

