// ── Onion routing ─────────────────────────────────────────────────────────────

export async function buildOnionPacket(
  hops: OnionHopFfi[],
  topicId: Uint8Array,
  op: Uint8Array,
): Promise<Uint8Array> {
  const base64 = await native.buildOnionPacket(hops, bytesToBase64(topicId), bytesToBase64(op));
  return base64ToBytes(base64);
}

export async function peelOnionLayer(
  packet: Uint8Array,
  recipientSeedHex: string,
): Promise<OnionPeeled> {
  const raw = await native.peelOnionLayer(bytesToBase64(packet), recipientSeedHex);
  return {
    peelType: raw.peelType as 'forward' | 'deliver',
    nextHopUrl: raw.nextHopUrl,
    innerPacket: raw.innerPacketBase64 ? base64ToBytes(raw.innerPacketBase64) : null,
    topicId: raw.topicIdBase64 ? base64ToBytes(raw.topicIdBase64) : null,
    op: raw.opBase64 ? base64ToBytes(raw.opBase64) : null,
  };
}

// ── Email ─────────────────────────────────────────────────────────────────────

export async function prepareOutboundEmail(params: {
  to: string;
  subject: string;
  bodyText: string;
  bodyHtml?: string;
  replyToMessageId?: string;
}): Promise<{ signedPayload: string; signature: string }> {
  const raw = await native.prepareOutboundEmail(
    params.to,
    params.subject,
    params.bodyText,
    params.bodyHtml ?? null,
    params.replyToMessageId ?? null,
  );
  const parsed = JSON.parse(raw) as { signed_payload: string; signature: string };
  return { signedPayload: parsed.signed_payload, signature: parsed.signature };
}
